Console.WriteLine("Structure : P(gagne=0.5) -> Facteur conditionnel -> gain (+1000 ou -500)");

// Affichage du factor graph du modele de loterie
// Le graphe montre la structure conditionnelle : gagne (Bernoulli) -> gain (deterministe selon l'etat)
display(HTML(FactorGraphHelper.GetLatestFactorGraphHtml()));

// Exploration : trouvez votre equivalent certain

// Supposons que votre equivalent certain est X* = 400 EUR
// Cela revele votre fonction d'utilite !

double equivalentCertain = 400; // <- Modifiez cette valeur selon votre preference

// Si vous etes indifferent entre X* certain et [0.5:1000, 0.5:0]
// Alors U(X*) = 0.5 * U(1000) + 0.5 * U(0)

// Pour CRRA : U(x) = x^(1-rho) / (1-rho) pour rho != 1
//           = ln(x) pour rho = 1

// NOTE IMPORTANTE : Pour les loteries incluant 0, on utilise U(epsilon)
// car CRRA n'est pas definie en 0 pour rho >= 1

double epsilon = 1.0; // Richesse minimale pour eviter U(0) = -infini

// Fonction CRRA avec protection contre les valeurs extremes
Func<double, double, double> CRRA = (x, rho) => {
    if (x < epsilon) x = epsilon;
    if (Math.Abs(rho - 1.0) < 0.01) return Math.Log(x);
    return Math.Pow(x, 1 - rho) / (1 - rho);
};

// Recherche de rho par resolution de l'equation d'indifference
// U(CE) = 0.5 * U(1000) + 0.5 * U(epsilon)

double FindRho(double ce, double high, double low, double p)
{
    double rhoMin = 0.01, rhoMax = 10.0;

    for (int i = 0; i < 100; i++)
    {
        double rho = (rhoMin + rhoMax) / 2;

        double U_ce = CRRA(ce, rho);
        double U_high = CRRA(high, rho);
        double U_low = CRRA(low, rho);
        double EU_loterie = p * U_high + (1 - p) * U_low;

        // On cherche rho tel que U_ce = EU_loterie
        // Si U_ce > EU_loterie, l'agent est moins averse => reduire rho
        if (U_ce > EU_loterie)
            rhoMax = rho;
        else
            rhoMin = rho;

        if (Math.Abs(rhoMax - rhoMin) < 0.0001) break;
    }
    return (rhoMin + rhoMax) / 2;
}

double rho = FindRho(equivalentCertain, 1000, epsilon, 0.5);

Console.WriteLine($"Equivalent certain : {equivalentCertain} EUR");
Console.WriteLine($"Loterie : 50% de 1000 EUR, 50% de {epsilon} EUR");
Console.WriteLine($"Coefficient d'aversion au risque (rho) estime : {rho:F2}");
Console.WriteLine();

if (rho < 0.5)
    Console.WriteLine("Profil : Faible aversion au risque (proche de la neutralite)");
else if (rho < 1.5)
    Console.WriteLine("Profil : Aversion au risque moderee (profil equilibre)");
else if (rho < 3.0)
    Console.WriteLine("Profil : Aversion au risque significative (profil prudent)");
else
    Console.WriteLine("Profil : Tres forte aversion au risque (profil conservateur)");

// Verification
double U_ce = CRRA(equivalentCertain, rho);
double EU_loterie = 0.5 * CRRA(1000, rho) + 0.5 * CRRA(epsilon, rho);

Console.WriteLine($" Verification de l'indifference :");
Console.WriteLine($"  U({equivalentCertain}) = {U_ce:F4}");
Console.WriteLine($"  E[U(loterie)] = {EU_loterie:F4}");
Console.WriteLine($"  Difference : {Math.Abs(U_ce - EU_loterie):F6} (devrait etre proche de 0)");

// Afficher quelques exemples de calibration
Console.WriteLine("--- Exemples de calibration ---");
Console.WriteLine("CE (EUR) | rho estime | Interpretation");
Console.WriteLine("---------|------------|----------------");
foreach (double ce in new[] { 200.0, 300.0, 400.0, 450.0, 480.0 })
{
    double r = FindRho(ce, 1000, epsilon, 0.5);
    string interp = r < 0.5 ? "Quasi-neutre" : r < 1.5 ? "Modere" : r < 3 ? "Prudent" : "Conservateur";
    Console.WriteLine($"{ce,8:F0} | {r,10:F2} | {interp}");
}

// Exercice 3 : Comparer les primes de risque CARA vs CRRA
