Console.WriteLine($"Loterie : {proba:P0} de +{gainHaut:N0} EUR, {(1-proba):P0} de {perteBasse:N0} EUR");
Console.WriteLine($"Valeur esperee du gain : {valeurEsperee:N0} EUR");
Console.WriteLine($"Richesse initiale : {richesseInitiale:N0} EUR");
Console.WriteLine();

